/**
 * @summary Get transactions for an account
 */
export const getGetAccountTransactionsUrl = (
  accountId: string,
  params?: GetAccountTransactionsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/accounts/${accountId}/transactions?${stringifiedParams}`
    : `/api/accounts/${accountId}/transactions`;
};

export const getAccountTransactions = async (
  accountId: string,
  params?: GetAccountTransactionsParams,
  options?: RequestInit,
): Promise<TransactionPage> => {
  return customFetch<TransactionPage>(
    getGetAccountTransactionsUrl(accountId, params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getGetAccountTransactionsQueryKey = (
  accountId: string,
  params?: GetAccountTransactionsParams,
) => {
  return [
    `/api/accounts/${accountId}/transactions`,
    ...(params ? [params] : []),
  ] as const;
};

